#include <stdio.h>
#include <string.h>
#define MAX 1000
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char R[MAX], S[MAX];
        scanf("%s %s", R, S);
        int freqR[26] = {0}, freqS[26] = {0};
        for (int i = 0; i < strlen(R); i++) {
            freqR[R[i] - 'a']++;
        }
        for (int i = 0; i < strlen(S); i++) {
            freqS[S[i] - 'a']++;
        }
        int correct = 1;
        for (int i = 0; i < 26; i++) {
            if (freqR[i] != freqS[i]) {
                correct = 0;
                break;
            }
        }
        if (correct) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

